import java.io.*;

public class InsecureDeserializationExample {
    public static void main(String[] args) {
        try {
            String userInput = "eyJpbml0IjoxMjMsInNjaGVtZSI6ImJhc2U2NCJ9";
            byte[] serializedData = java.util.Base64.getDecoder().decode(userInput);

            ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(serializedData));
            Object obj = ois.readObject();

            System.out.println("Deserialized object: " + obj);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    static class UserData implements Serializable {
        private int intValue;
        private String stringValue;

        public UserData(int intValue, String stringValue) {
            this.intValue = intValue;
            this.stringValue = stringValue;
        }

        @Override
        public String toString() {
            return "UserData{" +
                    "intValue=" + intValue +
                    ", stringValue='" + stringValue + '\'' +
                    '}';
        }
    }
}

